long long solution(vector<string> queryType, vector<vector<int>> query) {
    int len = (int)query.size();    
    int changeKey = 0, changeValue = 0;
    unordered_map<int, int> myMap;
    int ans = 0;
    for(int i = 0 ; i < len; i++)
    {
        string queryT = queryType[i];
        vector<int> keyVal = query[i];

        if(queryT == "insert")
        {
            int key = keyVal[0], val = keyVal[1];
            myMap[key - changeKey] = val - changeValue;
        }
        else if(queryT == "addToValue")
        {
            int val = keyVal[0];
            changeValue += val;
        }
        else if (queryT == "addToKey")
        {
            int key = keyVal[0];
            changeKey += key;
        } else {
            int key = keyVal[0];
            key -= changeKey;
            int value = myMap[key] + changeValue;
            ans += value;
        }
    }
    return ans;
}
