function solution(queryType, query) {
  let addedToKey = 0;
  let addedToValue = 0;
  const hashmap = {};
  let result = 0;

  for (let i = 0; i < queryType.length; i++) {
    if (queryType[i] === "insert") {
      const [key, value] = query[i];
      hashmap[key - addedToKey] = value - addedToValue;
    }
    if (queryType[i] === "addToKey") {
      addedToKey += query[i][0];
    }
    if (queryType[i] === "addToValue") {
      addedToValue += query[i][0];
    }
    if (queryType[i] === "get") {
      const key = query[i][0] - addedToKey;
      result += hashmap[key] + addedToValue;
    }
  }
  return result;
}
